-- ============================================================
-- RESET COMPLETO CRM — Nayade Experiences
-- Solo afecta datos del CRM, no TPV ni otros módulos
-- ============================================================

SET FOREIGN_KEY_CHECKS = 0;

-- 1. Logs y trazas (sin dependencias)
DELETE FROM crm_activity_log;
DELETE FROM cancellation_logs;
DELETE FROM document_number_logs;

-- 2. Anulaciones
DELETE FROM cancellation_requests;

-- 3. Pagos pendientes
DELETE FROM pending_payments;

-- 4. Operativos de reserva (solo los vinculados a reservas CRM)
DELETE FROM reservation_operational WHERE reservation_id IN (SELECT id FROM reservations);

-- 5. Bookings vinculados a reservas CRM
DELETE FROM bookings WHERE reservationId IS NOT NULL;

-- 6. Transacciones de origen CRM (no tocar las de TPV: tpvSaleId IS NOT NULL)
DELETE FROM transactions WHERE tpvSaleId IS NULL;

-- 7. Facturas
DELETE FROM invoices;

-- 8. Reservas
DELETE FROM reservations;

-- 9. Resetear contadores de documentos (PRES, RES, FAC, etc.)
UPDATE document_counters SET last_number = 0, last_reset_year = YEAR(NOW());

-- 10. Resetear auto_increment de las tablas principales
ALTER TABLE reservations AUTO_INCREMENT = 1;
ALTER TABLE invoices AUTO_INCREMENT = 1;
ALTER TABLE pending_payments AUTO_INCREMENT = 1;
ALTER TABLE reservation_operational AUTO_INCREMENT = 1;
ALTER TABLE bookings AUTO_INCREMENT = 1;
ALTER TABLE cancellation_requests AUTO_INCREMENT = 1;

SET FOREIGN_KEY_CHECKS = 1;

